sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }

   var fiscalYear = g_form.getValue('fiscal_year');
    if (!fiscalYear) return;

    var ga = new GlideAjax('IncentNowClientUtils');
    ga.addParam('sysparm_name', 'getFiscalDates');
    ga.addParam('sysparm_fiscalYear', fiscalYear);
    ga.addParam('sysparm_fiscalStartMonth', newValue);

    ga.getXMLAnswer(function (answer) {
        if (!answer) {
            g_form.showFieldMsg('fiscal_start', 'Could not calculate fiscal dates', 'error');
            return;
        }

        try {
            var data = JSON.parse(answer);

            if (data.start_date)
                g_form.setValue('start_date', data.start_date);

            if (data.end_date)
                g_form.setValue('end_date', data.end_date);

            if (data.fiscal_end)
                g_form.setValue('fiscal_end', data.fiscal_end); // numeric choice value

        } catch (e) {
            g_form.showFieldMsg('fiscal_start', 'Error calculating fiscal dates', 'error');
        }
    });

}
